B.KT=new A.eo("Bawang Merah","assets/images/img_bawang_merah.png","Bawang merah adalah umbi yang banyak digunakan sebagai bumbu dapur dan memiliki aroma kuat.","Membantu meningkatkan daya tahan tubuh, mengurangi peradangan, dan mendukung kesehatan jantung.","Dapat menyebabkan iritasi mata dan gangguan pencernaan jika dikonsumsi berlebihan.")
B.KQ=new A.eo("Bawang Putih","assets/images/img_bawang_putih.png","Bawang putih merupakan tanaman umbi dengan aroma khas yang sering digunakan sebagai bumbu dasar.","Mendukung kesehatan jantung, membantu meningkatkan imunitas, dan memiliki efek antibakteri alami.","Dapat menyebabkan bau mulut, mulas, dan iritasi lambung ketika konsumsi berlebih.")
B.KN=new A.eo("Brokoli","assets/images/img_brokoli.png","Brokoli adalah sayuran hijau yang kaya vitamin, mineral, dan serat.","Membantu detoksifikasi, menjaga kesehatan mata, dan mendukung sistem kekebalan tubuh.","Dapat menyebabkan kembung dan gas pada beberapa orang.")
B.KW=new A.eo("Cabai","assets/images/img_cabai.png","Cabai adalah buah pedas yang sering digunakan untuk menambah rasa pada makanan.","Meningkatkan metabolisme, membantu peredaran darah, dan kaya vitamin C.","Dapat menyebabkan iritasi lambung, heartburn, dan diare jika terlalu banyak.")
B.KV=new A.eo("Kentang","assets/images/img_kentang.png","Kentang adalah umbi yang menjadi sumber karbohidrat dan energi.","Memberikan energi, mendukung pencernaan, dan kaya vitamin B serta kalium.","Jika digoreng dapat meningkatkan kalori dan risiko kenaikan berat badan.")
B.KU=new A.eo("Kol","assets/images/img_kol.png","Kol adalah sayuran daun yang banyak digunakan dalam masakan Asia.","Membantu pencernaan, kaya vitamin C dan K, serta menjaga kesehatan kulit.","Dapat menyebabkan gas dan perut kembung bila dikonsumsi berlebihan.")
B.KO=new A.eo("Terong","assets/images/img_terong.png","Terong adalah sayuran berwarna ungu atau hijau dengan tekstur lembut.","Membantu mengontrol kadar gula darah, menjaga kesehatan jantung, dan kaya antioksidan.","Pada beberapa orang dapat menyebabkan alergi ringan atau gangguan pencernaan.")
B.KR=new A.eo("Mentimun","assets/images/img_mentimun.png","Mentimun adalah buah yang kaya air dan sering digunakan sebagai lalapan atau bahan salad.","Membantu hidrasi, menjaga kesehatan kulit, dan mendukung pencernaan.","Bila terlalu banyak dapat menyebabkan sering buang air kecil atau kembung.")
B.KS=new A.eo("Tomat","assets/images/img_tomat.png","Tomat adalah buah yang banyak digunakan dalam masakan dan kaya antioksidan.","Mendukung kesehatan mata, menjaga kesehatan jantung, dan baik untuk kulit.","Dapat menyebabkan asam lambung meningkat pada beberapa orang.")
B.KP=new A.eo("Wortel","assets/images/img_wortel.png","Wortel adalah sayuran berwarna oranye yang kaya beta-karoten.","Membantu menjaga kesehatan mata, meningkatkan imunitas, dan baik untuk kulit.","Konsumsi berlebihan dapat membuat kulit agak kekuningan (karotenemia).")
B.jX=s([B.KT,B.KQ,B.KN,B.KW,B.KV,B.KU,B.KO,B.KR,B.KS,B.KP],A.am("w<eo>"))
